const permissionMap = {
    Owner: new Set([
        "org:read",
        "org:write",
        "member:read",
        "member:write",
        "endpoint:read",
        "endpoint:write",
        "incident:read",
        "incident:write",
        "channel:read",
        "channel:write",
        "dashboard:read"
    ]),
    Admin: new Set([
        "org:read",
        "member:read",
        "endpoint:read",
        "endpoint:write",
        "incident:read",
        "incident:write",
        "channel:read",
        "channel:write",
        "dashboard:read"
    ]),
    Editor: new Set([
        "org:read",
        "endpoint:read",
        "endpoint:write",
        "incident:read",
        "incident:write",
        "channel:read",
        "channel:write",
        "dashboard:read"
    ]),
    Viewer: new Set(["org:read", "endpoint:read", "incident:read", "dashboard:read", "channel:read"])
};
export function hasPermission(role, permission) {
    return permissionMap[role].has(permission);
}
export function assertPermission(role, permission) {
    if (!hasPermission(role, permission)) {
        throw new Error(`Role ${role} lacks permission ${permission}`);
    }
}
